import React, { useState } from "react";
import "../styles/GeneralChat.css";

const greetings = ["hi", "hello", "hey", "hai", "thanks", "thank"];

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello. I'm glad you reached out today. How are you feeling right now?"
    }
  ]);
  const [input, setInput] = useState("");

  const therapistReply = (userText, previousMessages) => {
    const text = userText.toLowerCase().trim();
    
    // Get last therapist message to know what they asked
    const lastTherapistMsg = previousMessages
      .slice()
      .reverse()
      .find(msg => msg.sender === "bot")?.text.toLowerCase() || "";

    // Check what the bot last asked about
    const lastAskedAbout = {
      feeling: lastTherapistMsg.includes("how are you feeling"),
      energyType: lastTherapistMsg.includes("emotional stress") || lastTherapistMsg.includes("draining your energy"),
      stressType: lastTherapistMsg.includes("what kind") || lastTherapistMsg.includes("type of"),
      stressSpecific: lastTherapistMsg.includes("workload") || lastTherapistMsg.includes("performance") || lastTherapistMsg.includes("worry"),
      concernType: lastTherapistMsg.includes("what's bothering") || lastTherapistMsg.includes("what's concerning"),
      duration: lastTherapistMsg.includes("how long") || lastTherapistMsg.includes("when did you"),
      impact: lastTherapistMsg.includes("affecting you") || lastTherapistMsg.includes("how has this")
    };

    // Extract user's answer details
    const userMentions = {
      emotional: text.includes("emotional"),
      physical: text.includes("physical"),
      combination: text.includes("combination") || text.includes("both"),
      exams: text.includes("exam"),
      school: text.includes("school") || text.includes("study"),
      work: text.includes("work") || text.includes("job"),
      family: text.includes("family"),
      performance: text.includes("performance") || text.includes("marks") || text.includes("grade"),
      workload: text.includes("workload") || text.includes("too much"),
      worry: text.includes("worry") || text.includes("anxious") || text.includes("fear"),
      pressure: text.includes("pressure") || text.includes("expectations"),
      comparison: text.includes("comparison") || text.includes("others"),
      future: text.includes("future") || text.includes("career")
    };

    // Greeting responses
    if (["hi", "hello", "hey", "hai"].some(g => text === g)) {
      return "Hello. I'm glad you reached out today. How are you feeling right now?";
    }

    // If bot asked about energy type and user mentions combination
    if (lastAskedAbout.energyType && userMentions.combination) {
      return "I see - both emotional and physical exhaustion. That's a heavy load to carry. Let me ask more specifically - what's the main source of this stress? Is it related to exams, work, family, or something else?";
    }

    // If bot asked about energy type and user mentions emotional
    if (lastAskedAbout.energyType && userMentions.emotional && !userMentions.physical) {
      return "Emotional exhaustion can be draining in its own way. What's causing this emotional stress? Can you tell me what's weighing on your mind?";
    }

    // If bot asked about energy type and user mentions physical
    if (lastAskedAbout.energyType && userMentions.physical && !userMentions.emotional) {
      return "Physical exhaustion affects our whole wellbeing. What's been draining you physically? Is it lack of sleep, overwork, or something else?";
    }

    // User mentions exam/education stress
    if ((userMentions.exams || userMentions.school) && !lastAskedAbout.stressSpecific) {
      return "Exams and studies can be really stressful. When it comes to your exams, what's bothering you most - is it the workload, worry about your performance, the competition with others, or something else?";
    }

    // User mentions performance (after being asked what's bothering them about exams)
    if (userMentions.performance && (lastAskedAbout.stressSpecific || lastAskedAbout.concernType)) {
      return "Performance anxiety is something many students struggle with. Tell me more - is it that you're worried you won't do well enough, or that you won't meet someone's expectations? What does good performance look like to you?";
    }

    // User mentions workload
    if (userMentions.workload && (lastAskedAbout.stressSpecific || lastAskedAbout.concernType)) {
      return "Too much workload can feel overwhelming. How much time do you have before the exams? And what subjects or topics feel most manageable versus most difficult?";
    }

    // User mentions worry/anxiety about exams
    if (userMentions.worry && (userMentions.exams || userMentions.school)) {
      return "Worry about exams is common. When you think about the exam, what specifically worries you most - failing, disappointing someone, not being good enough, or something else?";
    }

    // User mentions work/job stress
    if (userMentions.work && !lastAskedAbout.stressSpecific) {
      return "Work stress can really drain you. What aspect of work is most stressful right now - is it the workload, relationships with colleagues, pressure from your boss, or something else?";
    }

    // User mentions family stress
    if (userMentions.family) {
      return "Family can be a source of both support and stress. What specifically about your family situation is weighing on you right now? Are they pressuring you about something?";
    }

    // User mentions pressure/expectations
    if (userMentions.pressure) {
      return "Pressure and expectations can be really heavy to carry. Whose expectations do you feel most? Your own, your family's, your school's, or someone else's? And what happens if you don't meet them?";
    }

    // User mentions comparison with others
    if (userMentions.comparison) {
      return "Comparing yourself to others can be really painful. Tell me - who do you compare yourself to most, and what specifically makes you feel like you're not measuring up?";
    }

    // User answers about future/career concerns
    if (userMentions.future) {
      return "Worrying about your future is understandable. What specific fears do you have about your future? What are you most afraid won't happen, or what are you afraid will happen?";
    }

    // If answering follow-up about performance concerns
    if (lastAskedAbout.impact && (userMentions.performance || userMentions.worry)) {
      return "So it sounds like the worry about performance is really affecting you. In what ways is this showing up in your life - is it affecting your sleep, your concentration, your mood, or all of these?";
    }

    // Generic follow-up for any elaboration
    if (text.length > 10) {
      return "Thank you for sharing that. That gives me a better picture. Can you tell me more about how this has been making you feel day to day?";
    }

    return "I want to understand better. Can you tell me a bit more about that?";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input, messages)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to share your feelings</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${msg.sender === "user" ? "user-group" : "therapist-group"}`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender === "user" ? "user" : "bot"}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Share your thoughts safely..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
